import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import puppeteer from "puppeteer";
import { marked } from "marked";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const inputFile = path.join(__dirname, "TICKETING-SYSTEM-DESIGN-v6.md");
const outputFile = path.join(__dirname, "TICKETING-SYSTEM-DESIGN-v6.pdf");

const markdown = fs.readFileSync(inputFile, "utf8");

const renderer = {
  code({ text, lang }) {
    const escaped = text
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");
    if (lang === "mermaid") {
      return `<div class="mermaid-block"><pre class="mermaid-source">${escaped}</pre></div>`;
    }
    const langClass = lang ? ` class="language-${lang}"` : "";
    return `<pre class="code-block"><code${langClass}>${escaped}</code></pre>`;
  },
};

marked.use({
  gfm: true,
  breaks: false,
  renderer,
});

const bodyHtml = marked.parse(markdown);

const html = `<!DOCTYPE html>
<html lang="fa" dir="rtl">
<head>
  <meta charset="UTF-8" />
  <title>Ticketing System Design v6</title>
  <link rel="preconnect" href="https://fonts.googleapis.com" />
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
  <link href="https://fonts.googleapis.com/css2?family=Vazirmatn:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet" />
  <script src="https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.min.js"></script>
  <style>
    :root {
      --text: #1a1a1a;
      --muted: #555;
      --border: #d0d7de;
      --bg-code: #f6f8fa;
      --accent: #0969da;
    }

    * { box-sizing: border-box; }

    @page {
      size: A4;
      margin: 18mm 14mm 20mm 14mm;
    }

    html, body {
      margin: 0;
      padding: 0;
      background: #fff;
      color: var(--text);
      font-family: "Vazirmatn", Tahoma, "Segoe UI", sans-serif;
      font-size: 11pt;
      line-height: 1.65;
      -webkit-print-color-adjust: exact;
      print-color-adjust: exact;
    }

    .page {
      max-width: 100%;
      padding: 0;
    }

    h1, h2, h3, h4 {
      color: #111;
      line-height: 1.35;
      page-break-after: avoid;
      break-after: avoid;
    }

    h1 {
      font-size: 22pt;
      margin: 0 0 12pt;
      border-bottom: 2px solid var(--border);
      padding-bottom: 8pt;
    }

    h2 {
      font-size: 16pt;
      margin: 22pt 0 10pt;
      border-bottom: 1px solid var(--border);
      padding-bottom: 5pt;
    }

    h3 {
      font-size: 13pt;
      margin: 16pt 0 8pt;
    }

    p, blockquote, ul, ol, table, pre, .mermaid-block {
      page-break-inside: avoid;
      break-inside: avoid-page;
    }

    blockquote {
      margin: 10pt 0;
      padding: 8pt 12pt;
      border-right: 4px solid var(--accent);
      background: #f8fafc;
      color: var(--muted);
    }

    hr {
      border: none;
      border-top: 1px solid var(--border);
      margin: 18pt 0;
    }

    table {
      width: 100%;
      border-collapse: collapse;
      margin: 10pt 0 14pt;
      font-size: 10pt;
      table-layout: fixed;
      word-wrap: break-word;
    }

    th, td {
      border: 1px solid var(--border);
      padding: 6pt 8pt;
      vertical-align: top;
      text-align: right;
    }

    th {
      background: #f3f4f6;
      font-weight: 700;
    }

    tr { page-break-inside: avoid; break-inside: avoid; }

    code {
      font-family: "JetBrains Mono", Consolas, monospace;
      font-size: 9pt;
      direction: ltr;
      unicode-bidi: embed;
      background: #eef2f7;
      padding: 1pt 4pt;
      border-radius: 3pt;
    }

    pre.code-block {
      direction: ltr;
      text-align: left;
      background: var(--bg-code);
      border: 1px solid var(--border);
      border-radius: 6pt;
      padding: 10pt 12pt;
      overflow-x: auto;
      margin: 10pt 0 14pt;
      white-space: pre-wrap;
      word-break: break-word;
    }

    pre.code-block code {
      background: transparent;
      padding: 0;
      font-size: 8.5pt;
      line-height: 1.5;
    }

    .mermaid-block {
      margin: 14pt 0 18pt;
      padding: 10pt;
      border: 1px solid var(--border);
      border-radius: 8pt;
      background: #fff;
      overflow: visible;
      text-align: center;
    }

    .mermaid-block svg {
      max-width: 100% !important;
      height: auto !important;
    }

    .mermaid-source { display: none; }

    ul, ol { padding-right: 20pt; }
    li { margin: 3pt 0; }

    strong { font-weight: 700; }
  </style>
</head>
<body>
  <div class="page">${bodyHtml}</div>
  <script>
    mermaid.initialize({
      startOnLoad: false,
      theme: "default",
      securityLevel: "loose",
      fontFamily: "Vazirmatn, Tahoma, sans-serif",
      flowchart: { useMaxWidth: true, htmlLabels: true },
      sequence: { useMaxWidth: true, wrap: true },
      er: { useMaxWidth: true }
    });

    async function renderAllMermaid() {
      const blocks = document.querySelectorAll(".mermaid-block");
      let index = 0;
      for (const block of blocks) {
        const source = block.querySelector(".mermaid-source");
        if (!source) continue;
        const graph = source.textContent.trim();
        const id = "mmd-" + (++index);
        try {
          const { svg } = await mermaid.render(id, graph);
          block.innerHTML = svg;
        } catch (err) {
          block.innerHTML = '<pre style="color:#b42318;direction:ltr;text-align:left;">Mermaid render error: ' +
            String(err.message || err) + "\\n\\n" + graph + "</pre>";
        }
      }
      window.__mermaidDone = true;
    }

    renderAllMermaid().catch((err) => {
      console.error(err);
      window.__mermaidDone = true;
    });
  </script>
</body>
</html>`;

const browser = await puppeteer.launch({
  headless: true,
  args: ["--no-sandbox", "--disable-setuid-sandbox"],
});

try {
  const page = await browser.newPage();
  await page.setViewport({ width: 1400, height: 2000, deviceScaleFactor: 2 });
  await page.setContent(html, { waitUntil: "networkidle0", timeout: 120000 });
  await page.waitForFunction(() => window.__mermaidDone === true, { timeout: 120000 });

  // Allow SVG layout to settle after mermaid render
  await new Promise((r) => setTimeout(r, 1500));

  await page.pdf({
    path: outputFile,
    format: "A4",
    printBackground: true,
    preferCSSPageSize: false,
    margin: {
      top: "18mm",
      right: "14mm",
      bottom: "20mm",
      left: "14mm",
    },
  });

  const stats = fs.statSync(outputFile);
  console.log(`PDF created: ${outputFile}`);
  console.log(`Size: ${(stats.size / 1024 / 1024).toFixed(2)} MB`);
} finally {
  await browser.close();
}

