mermaid.initialize({
  startOnLoad: false,
  theme: "default",
  securityLevel: "loose",
  fontFamily: "Vazirmatn, Tahoma, sans-serif",
  themeVariables: {
    fontSize: "10px",
    actorFontSize: "10px",
    noteFontSize: "9px",
    signalFontSize: "9px",
  },
  flowchart: {
    useMaxWidth: true,
    htmlLabels: true,
    nodeSpacing: 12,
    rankSpacing: 20,
    padding: 8,
  },
  sequence: {
    useMaxWidth: true,
    wrap: true,
    diagramMarginX: 8,
    diagramMarginY: 8,
    actorMargin: 40,
    messageMargin: 22,
    boxMargin: 6,
  },
  er: {
    useMaxWidth: true,
    layoutDirection: "TB",
    minEntityWidth: 80,
    minEntityHeight: 40,
  },
});

function fitMermaidBlock(block) {
  const svg = block.querySelector("svg");
  if (!svg) return;

  const wrap = document.createElement("div");
  wrap.className = "mermaid-fit";
  svg.parentNode.insertBefore(wrap, svg);
  wrap.appendChild(svg);

  const maxWidth = 640;
  const maxHeights = { flow: 220, sequence: 280, erd: 360 };
  const type = block.classList.contains("mermaid-erd")
    ? "erd"
    : block.classList.contains("mermaid-sequence")
      ? "sequence"
      : "flow";
  const maxHeight = maxHeights[type] || 300;

  const rect = svg.getBoundingClientRect();
  const width = rect.width || svg.viewBox?.baseVal?.width || 800;
  const height = rect.height || svg.viewBox?.baseVal?.height || 400;
  const scale = Math.min(1, maxWidth / width, maxHeight / height);

  if (scale < 1) {
    wrap.style.transform = "scale(" + scale + ")";
    wrap.style.width = width + "px";
    block.style.height = Math.ceil(height * scale + 12) + "px";
  }
}

async function renderAllMermaid() {
  const blocks = document.querySelectorAll(".mermaid-block");
  let index = 0;
  for (const block of blocks) {
    const source = block.querySelector(".mermaid-source");
    if (!source) continue;
    const graph = source.textContent.trim();
    const id = "mmd-" + (++index);
    try {
      const { svg } = await mermaid.render(id, graph);
      block.innerHTML = svg;
      fitMermaidBlock(block);
    } catch (err) {
      block.innerHTML =
        '<pre style="color:#b42318;direction:ltr;text-align:left;font-size:9pt;">Mermaid render error: ' +
        String(err.message || err) +
        "</pre>";
    }
  }
  window.__mermaidDone = true;
}

